8af643cc-df2c-49f7-a2cd-428c139b0ecc	ion - DevSecOps practices - Risk assessment workflows Architectural Notes - The platform integrates with Palmyra’s domain model to map vulnerabilities to modules, versions, and dependencies. - Historical tracking enables teams to visualize vulnerability evolution and prioritize remediation. - Automated ingestion pipelines ensure up‑to‑date vulnerability data with minimal manual intervention. - Kubernetes deployments ensure resilience, scalability, and consistent behavior across environments. - The architecture supports future extensions such as CVE enrichment, severity scoring, and automated remediation suggestions.	{"loc": {"lines": {"to": 1, "from": 1}}, "source": "blob", "file_id": "1JZzCJaBsmXqegSR66xvJddbT-AYy8ziZ", "blobType": "text/plain", "file_title": "palmyra-vulnerabilities-referance.txt"}	[0.005918188,0.03961084,0.1279214,0.014727108,0.031120945,0.038178496,-0.019740315,0.012441867,-0.012012163,0.04125153,0.019662187,-0.025170203,0.007357043,-0.011823354,0.003720841,0.023217006,0.03354291,0.01920644,-0.04867368,0.013411955,0.014297404,0.0008960293,-0.008450834,0.006097231,-0.02711038,0.008437812,-0.028099999,0.022123216,0.027839573,-0.017070945,0.040418163,-0.021836746,-0.035782576,0.048178867,0.024987904,-0.00057985546,-0.011361098,0.0026856463,-0.04427247,0.07484652,-0.022904495,0.0054233777,-0.06307525,0.06276274,-0.019141333,-0.0048341635,-0.032370992,0.0048764828,-0.029506302,0.00890658,-0.008776367,-0.03244912,0.02662859,0.0013761902,-0.0076955976,-0.024701435,-0.031693883,0.04700695,-0.039168116,0.025873354,-0.009805051,-0.031719923,0.018125672,0.0007121032,-0.039037906,0.016094346,-0.041954678,-0.016003197,0.013242678,0.012344207,0.05036645,0.004980653,0.0022982622,0.0013835147,0.026954124,-0.00076988526,0.009440454,0.030157367,0.0379962,0.02049555,0.0004968446,-0.014792214,-0.04286617,-0.040522333,-0.01593809,-0.046850692,-0.03067822,0.017943373,-0.030964687,0.005364782,-0.024167562,0.031902224,-0.035105467,0