c41d02d0-09ef-407b-8fef-e42f68ec960b	Technical Contributions - Designed and implemented REST APIs for session creation, message persistence, and conversation retrieval. - Built communication layers using Spring Web (RestTemplate) to interact with Python AI services. - Implemented persistence logic using Spring Data repositories for storing sessions and messages. - Developed prompt‑optimization strategies to improve AI response quality and reduce hallucinations. - Containerized microservices using Docker and deployed them on Kubernetes clusters for scalability and reliability. - Authored documentation and integration guidelines for QA and development teams.	{"loc": {"lines": {"to": 1, "from": 1}}, "source": "blob", "file_id": "1gn5gyDJyBi9w_bV_agkWgEqY6y9g43gS", "blobType": "text/plain", "file_title": "veggo-ai-chatbot.txt"}	[0.025779534,-0.013297671,0.07200866,-0.013080123,0.031598967,-0.009619737,-0.0191307,0.06656994,0.008729146,-0.013209293,0.014779723,-0.013827947,-0.030103318,-0.017390309,-0.019198684,0.039811432,-0.0006700673,0.0021092037,-0.0335841,0.037119266,0.014630158,0.03600433,0.008015314,0.019470619,0.009218631,-0.014779723,-0.022733852,0.05294594,-0.037690334,-0.08517036,0.019484216,-0.02877083,-0.043210633,0.025222067,0.0012381587,-0.015309998,-0.0052347686,0.02495013,0.008144484,-0.004653505,0.014521384,-0.028662058,0.033692874,0.026976053,-0.029151542,0.023155352,-0.008538791,0.011795225,0.005452317,0.014167867,-0.058520634,0.016887227,0.03714646,0.04440715,-0.002240073,0.005768443,0.006879981,-0.00093647966,-0.02269306,0.025929099,0.011509692,0.0025867915,0.01751268,0.024705388,-0.047969513,-0.02728878,-0.029695414,-0.056562692,-0.011876806,0.0048132674,0.034372713,0.045848414,-0.04106234,-0.029477865,-0.012427476,-0.025194872,-0.010408351,0.06548219,-0.031544577,-0.03380165,-0.056725856,-0.00531295,-0.0049322397,-0.00025557738,-0.021115832,-0.022883417,-0.015160433,-0.0087359445,-0.030592803,-0.056073207,0.0023522465,0.054468784,-0.027479135,0.00