7e113e36-cea1-4f66-9f44-1750e1e96b5d	Architectural Notes - The backend maintained conversation context through persistent session and message entities, enabling multi‑turn reasoning. - Prompt optimization was iterative and based on real usage patterns to improve AI accuracy and reduce noise. - The architecture decoupled the Java backend from the Python AI service, allowing independent scaling and updates. - Kubernetes ensured resilience, autoscaling, and consistent deployment across environments. - The design supported future extensions such as user‑specific context, advanced analytics, and multi‑model routing.	{"loc": {"lines": {"to": 1, "from": 1}}, "source": "blob", "file_id": "1gn5gyDJyBi9w_bV_agkWgEqY6y9g43gS", "blobType": "text/plain", "file_title": "veggo-ai-chatbot.txt"}	[0.009696883,0.0056257257,0.06948852,0.002331853,0.03889907,0.039875034,-0.0023649659,0.035999067,-0.023172135,0.012764193,0.02530531,-0.0711616,-0.027731273,0.00980145,-0.04046061,-0.00341064,0.01292453,-0.018557226,-0.019031266,-0.011718519,0.008365392,0.0006413467,0.02399473,-0.016967803,0.0013419483,-0.015977899,-0.0082887085,0.037867337,-0.009912989,-0.060342357,0.012220443,-0.010972605,-0.04930004,0.027480312,-0.03655676,-0.03572022,-0.015085589,-0.009160104,0.03301541,0.02230771,-0.0019536675,0.005956856,-0.017469727,0.045926,-0.0032834162,0.01965867,0.009006739,0.023297615,-0.0035552913,0.044476,-0.04614908,0.033545222,-0.0040676715,0.0042070947,-0.03360099,-0.0013785468,0.009104335,0.010024528,0.011871885,0.024189925,0.018877901,-0.04966254,0.022265883,0.014235108,-0.046316385,-0.018222611,-0.038313493,0.012401693,0.015908187,0.006396039,0.025737522,0.02969714,-0.04154811,-0.041575998,0.016256744,-0.025054349,-0.0012792078,0.040349074,0.02686685,-0.024538482,-0.035274066,0.032123104,-0.0014360589,-0.042998113,0.018222611,-0.04352792,-0.00074068573,0.013001213,-0.08270584,-0.014681262,0.0163404,0.060565434,-0.018863957,0.010212749,0.07015775,0.027089927,0.03909426,0.011627894,0.01639